/* Lightweight loader that imports the pdf.js worker from UNPKG CDN.
   This avoids Vite module import issues during dev and ensures the
   worker is served from the app's static `public/` path.
   If you prefer to ship the worker locally, replace the URL below
   with a local copy (e.g. copy node_modules/pdfjs-dist/... to public/).
*/
(function(){
  try {
    importScripts('https://unpkg.com/pdfjs-dist@5.4.530/legacy/build/pdf.worker.min.js');
  } catch(e) {
    // fallback: nothing to do, errors will surface in the main thread
    console.error('Failed to import pdf.worker from CDN', e);
  }
})();
